import React from 'react';
import { useNavigate } from 'react-router-dom';

const Dashboard = ({ schedule, setSchedule }) => {
    const navigate = useNavigate();

    // 1. Calculate Progress
    const completedCount = schedule ? schedule.filter(t => t.status === 'completed').length : 0;
    const totalTasks = schedule ? schedule.length : 0;
    const progress = totalTasks > 0 ? (completedCount / totalTasks) * 100 : 0;

    // 2. Clear Plan Function
    const handleResetPlan = () => {
        if (window.confirm("Congratulations on finishing! Do you want to clear this plan and start a new one?")) {
            localStorage.removeItem('studyPulse_Plan'); // Remove from storage
            setSchedule(null); // Reset state in App.js
            navigate('/dashboard'); // Refresh view
        }
    };

    return (
        <div style={{ padding: '40px', maxWidth: '800px', margin: '0 auto' }}>
            <h1>Your Study Roadmap</h1>
            
            {!schedule ? (
                <div>
                    <p>No plan active. Go to the generator to start.</p>
                    {/* Your existing Form/Generate button here */}
                </div>
            ) : (
                <>
                    {/* Progress Bar */}
                    <div style={{ width: '100%', height: '20px', background: '#eee', borderRadius: '10px', marginBottom: '10px', overflow: 'hidden' }}>
                        <div style={{ 
                            width: `${progress}%`, 
                            background: '#4CAF50', 
                            height: '100%', 
                            transition: 'width 0.5s ease-in-out' 
                        }} />
                    </div>
                    <p style={{ fontWeight: 'bold', textAlign: 'right' }}>{Math.round(progress)}% Completed</p>

                    {/* Schedule List */}
                    <div style={{ marginTop: '20px' }}>
                        {schedule.map((item) => (
                            <div key={item.day} style={{ padding: '15px', borderBottom: '1px solid #ddd' }}>
                                <strong>Day {item.day}:</strong> {item.topic} - {item.status}
                            </div>
                        ))}
                    </div>

                    {/* FIX: Show Reset Button ONLY at 100% */}
                    {progress === 100 && (
                        <div style={{ marginTop: '40px', textAlign: 'center', padding: '20px', background: '#f0fff4', borderRadius: '10px', border: '1px solid #38a169' }}>
                            <h2 style={{ color: '#2f855a' }}>🎉 All Topics Completed!</h2>
                            <button 
                                onClick={handleResetPlan}
                                style={{ 
                                    marginTop: '15px', 
                                    padding: '12px 25px', 
                                    background: '#e74c3c', 
                                    color: 'white', 
                                    border: 'none', 
                                    borderRadius: '5px', 
                                    cursor: 'pointer',
                                    fontWeight: 'bold'
                                }}
                            >
                                Clear and Start New Plan
                            </button>
                        </div>
                    )}
                </>
            )}
        </div>
    );
};

export default Dashboard;
